pub async fn search_code(
    state: &Arc<AppState>,
    params: SearchCodeParams,
) -> anyhow::Result<CallToolResult> {
    crate::ensure_embedding_ready!(state);

    let SearchCodeParams {
        query,
        project_id,
        limit,
    } = params;
    let project_id = normalize_project_id(project_id);

    let mut is_partial = false;
    let mut indexing_message = None;

    let mut project_status = None;
    if let Some(ref project_id) = project_id {
        if let Ok(Some(status)) = state.storage.get_index_status(project_id).await {
            if status.status == crate::types::IndexState::Indexing
                || status.status == crate::types::IndexState::EmbeddingPending
            {
                is_partial = true;
                indexing_message = Some(format!(
                    "Indexing in progress ({}/{} files). Results may be incomplete.",
                    status.indexed_files, status.total_files
                ));
            }
            project_status = Some(status);
        }
    }

    let query_embedding = state.embedding.embed(&query).await?;

    let limit = normalize_limit(limit);

    // Run vector search and BM25 in parallel for robust results.
    // Previously BM25 was only a fallback — degenerate vectors masked BM25 entirely.
    let project_id = project_id.as_deref();
    let (vector_results, bm25_results) = tokio::join!(
        async {
            match state
                .storage
                .vector_search_code(&query_embedding, project_id, limit)
                .await
            {
                Ok(results) => {
                    tracing::debug!(hits = results.len(), "search_code: vector search completed");
                    results
                }
                Err(e) => {
                    tracing::warn!(error = %e, "search_code: vector search failed, falling back to empty");
                    Vec::new()
                }
            }
        },
        async {
            state
                .code_search
                .search(&query, project_id, limit, state.storage.as_ref())
                .await
        }
    );

    // Merge: vector results first, then BM25 results not already present.
    // This gives vector priority in ranking while ensuring BM25 fills gaps.
    use std::collections::HashSet;
    let mut seen_ids: HashSet<String> = HashSet::new();
    let mut merged = Vec::with_capacity(limit);

    for r in &vector_results {
        if seen_ids.insert(r.id.clone()) {
            merged.push(json!({
                "id": r.id,
                "file_path": r.file_path,
                "content": r.content,
                "language": r.language,
                "start_line": r.start_line,
                "end_line": r.end_line,
                "chunk_type": r.chunk_type,
                "name": r.name,
                "context_path": r.context_path,
                "score": r.score,
                "source": "vector"
            }));
        }
        if merged.len() >= limit {
            break;
        }
    }

    for r in &bm25_results {
        if merged.len() >= limit {
            break;
        }
        if seen_ids.insert(r.id.clone()) {
            merged.push(json!({
                "id": r.id,
                "file_path": r.file_path,
                "content": r.content,
                "language": r.language,
                "start_line": r.start_line,
                "end_line": r.end_line,
                "chunk_type": r.chunk_type,
                "name": r.name,
                "context_path": r.context_path,
                "score": r.score,
                "source": "bm25"
            }));
        }
    }

    Ok(success_json(json!({
        "results": merged,
        "count": merged.len(),
        "summary": summary_collection_response(
            "collection",
            merged.len(),
            Some(merged.len()),
            is_partial,
            indexing_message.clone(),
        ),
        "query": query,
        "contract": code_search_contract_json(project_id, project_status.as_ref()),
        "vector_hits": vector_results.len(),
        "bm25_hits": bm25_results.len(),
        "is_partial": is_partial,
        "message": indexing_message
    })))
}

                })?;
                let status_params = GetIndexStatusParams { project_id };
                let status = logic::code::get_index_status(&self.state, status_params)
                    .await
                    .map_err(to_rpc_error)?;
                Ok(status)
            }
            "stats" => {
                let project_id = params.0.project_id.ok_or_else(|| ErrorData {
                    code: ErrorCode(-32602),
                    message: "project_id required for stats action".into(),
                    data: None,
                })?;
                let stats_params = GetProjectStatsParams { project_id };
                logic::code::get_project_stats(&self.state, stats_params)
                    .await
                    .map_err(to_rpc_error)
            }
            "projection" => {
                let project_id = params.0.project_id.ok_or_else(|| ErrorData {
                    code: ErrorCode(-32602),
                    message: "project_id required for projection action".into(),
                    data: None,
                })?;
                let projection_params = crate::server::params::GetProjectProjectionParams {
                    project_id,
                    relation_scope: params.0.relation_scope.clone(),
                    sort_mode: params.0.sort_mode.clone(),
                };
                logic::code::get_project_projection(&self.state, projection_params)
                    .await
                    .map_err(to_rpc_error)
            }
            "projection_by_locator" => {
                let locator = params.0.locator.ok_or_else(|| ErrorData {
                    code: ErrorCode(-32602),
                    message: "locator required for projection_by_locator action".into(),
                    data: None,
                })?;
                let locator_params = crate::server::params::GetProjectionByLocatorParams {
                    locator,
                };
                logic::code::get_project_projection_by_locator(&self.state, locator_params)
                    .await
                    .map_err(to_rpc_error)
            }
            other => Err(ErrorData {
                code: ErrorCode(-32602),
                message: format!("Invalid action '{}'. Use: list, status, stats, projection, projection_by_locator", other).into(),
                data: None,
            }),
        }
    }

    #[tool(description = "Delete indexed project.")]
    async fn delete_project(
        &self,
        params: Parameters<DeleteProjectParams>,
    ) -> Result<CallToolResult, ErrorData> {
        logic::code::delete_project(&self.state, params.0)
            .await
            .map_err(to_rpc_error)
    }

    #[tool(description = "Fast by-name code lookup. Symbol IDs are stable project-scoped symbol identities; responses include additive contract and summary metadata.")]
    async fn search_symbols(
        &self,
        params: Parameters<SearchSymbolsParams>,
    ) -> Result<CallToolResult, ErrorData> {
        logic::code::search_symbols(&self.state, params.0)
            .await
            .map_err(to_rpc_error)
    }

    #[tool(
        description = "Navigate code relationships for a symbol_id. Related traversal returns preferred exported nodes/edges plus additive contract and summary metadata; frontier is an unexpanded boundary hint, not a cursor."
    )]
    async fn symbol_graph(
        &self,
        params: Parameters<SymbolGraphParams>,
    ) -> Result<CallToolResult, ErrorData> {
        logic::code::symbol_graph(&self.state, params.0)
            .await
            .map_err(to_rpc_error)
    }

    #[tool(description = "DANGER: Reset all database data (requires confirm=true).")]
    async fn reset_all_memory(
        &self,
        params: Parameters<ResetAllMemoryParams>,
    ) -> Result<CallToolResult, ErrorData> {
        logic::system::reset_all_memory(&self.state, params.0)
            .await
            .map_err(to_rpc_error)
    }

    #[tool(description = "Meta-help tool. Returns concise usage guidance for the MCP tool surface.")]
    async fn how_to_use(
        &self,
        _params: Parameters<HowToUseParams>,
    ) -> Result<CallToolResult, ErrorData> {
        let text = [
            "=== TOOL GROUPS ===",
            "Memory: store_memory, update_memory, delete_memory, list_memories, get_memory, invalidate, get_valid",
            "Search: recall, search_memory, recall_code, search_symbols, symbol_graph",
            "Project: index_project, delete_project, project_info",
            "System: get_status, reset_all_memory, how_to_use",
            "",
            "For exact request/response fields, inspect each tool schema from list_tools.",
        ]
        .join("\n");

        Ok(CallToolResult::success(vec![Content::text(text)]))
    }
}

fn recall_code_response_keeps_core_contract_fields() {
        let response = json!({
            "results": [{
                "id": "local-1",
                "file_path": "src/graph/rrf.rs",
                "content": "pub fn rrf_merge() {}",
                "language": "rust",
                "start_line": 43,
                "end_line": 83,
                "chunk_type": "function",
                "name": "rrf_merge",
                "context_path": "mod:graph",
                "score": 0.91,
                "rrf_score": 0.90,
                "lexical_score": 0.12,
                "exact_score": 0.80,
                "vector_score": 0.75,
                "bm25_score": 11.0,
                "ppr_score": 0.2
            }],
            "count": 1,
            "query": "find rrf merge",
            "contract": { "compatibility": { "clients_must_ignore_unknown_fields": true } },
            "summary": { "result_kind": "collection", "partial": { "is_partial": false } },
            "weights": { "vector": 0.5, "bm25": 0.2, "ppr": 0.3 },
            "is_partial": false,
            "message": null,
            "_indexing": {
                "status": "embedding_pending",
                "degraded": ["vector_search"],
                "available": ["bm25_search", "symbol_search", "ppr_graph"]
            }
        });

        assert_eq!(response["query"], "find rrf merge");
        assert_eq!(response["count"], 1);
        assert!(response["results"].is_array());
        assert!(response["contract"].is_object());
        assert!(response["summary"].is_object());
        assert!(response["weights"].is_object());
        assert_eq!(response["is_partial"], false);
        assert_eq!(response["message"], serde_json::Value::Null);
        assert!(response["_indexing"].is_object());
        assert!(response.get("results_compact").is_none());
        assert!(response.get("readiness").is_none());
        assert!(response.get("warning").is_none());
        assert!(response.get("next_actions").is_none());
    }

