pub fn apply_hub_dampening(
    scores: &mut HashMap<NodeIndex, f32>,
    degrees: &HashMap<NodeIndex, usize>,
) {
    for (node, score) in scores.iter_mut() {
        if let Some(&degree) = degrees.get(node) {
            if degree > 0 {
                *score /= (degree as f32).sqrt();
            }
        }
    }
}

