        let vector = vec![("a".to_string(), 0.99), ("b".to_string(), 0.98)];
        let bm25 = vec![("b".to_string(), 0.99), ("a".to_string(), 0.98)];

        let results = rrf_merge(&vector, &bm25, &[], 0.1, 0.9, 0.0, 10);

        assert_eq!(results[0].0, "b");
        assert!(results[0].1.bm25_score > results[0].1.vector_score);
        assert!(results[0].1.combined_score > results[1].1.combined_score);
    }
}

fn lexical_rerank_score(
    chunk: &crate::types::ScoredCodeChunk,
    query_lower: &str,
    terms: &[String],
    codeish: bool,
) -> f32 {
    let path = chunk.file_path.to_lowercase();
    let name = chunk.name.clone().unwrap_or_default().to_lowercase();
    let ctx = chunk
        .context_path
        .clone()
        .unwrap_or_default()
        .to_lowercase();
    let content = chunk.content.to_lowercase();

    let mut raw = 0.0f32;
    let mut matched_terms = 0usize;
    let mut strong_hit = false;

    if query_lower.len() >= 4
        && (path.contains(query_lower) || name.contains(query_lower) || ctx.contains(query_lower))
    {
        raw += 1.8;
        strong_hit = true;
    }

    for term in terms {
        if term.len() < 2 {
            continue;
        }
        let in_name = !name.is_empty() && name.contains(term);
        let in_path = path.contains(term);
        let in_ctx = !ctx.is_empty() && ctx.contains(term);
        let in_content = content.contains(term);

        if in_name {
            raw += 0.7;
            matched_terms += 1;
            strong_hit = true;
        } else if in_path {
            raw += 0.55;
            matched_terms += 1;
            strong_hit = true;
        } else if in_ctx {
            raw += 0.45;
            matched_terms += 1;
        } else if in_content {
            raw += 0.2;
            matched_terms += 1;
        }
    }

    if !terms.is_empty() {
        raw += 0.8 * (matched_terms as f32 / terms.len() as f32);
    }

    if codeish && strong_hit {
        raw += 0.8;
    }

    // Penalize very short generic chunks unless they have strong lexical evidence.
    if chunk.content.len() < 96 && !strong_hit {
        raw -= 0.6;
    }

    raw.clamp(0.0, 4.0) / 4.0
}

