nce","locator_stability":"not_stable_until_materialization_strategy_changes","locator_survives_generation_change":false,"persistence":"ephemeral_contract_only","persistence_semantics":"contract is exposed on status surfaces only; no persisted projection artifact is promised yet","refresh_basis":"semantic_generation","shape_version":1,"shape_version_semantics":"materialized_projection_payload_shape_version","strategy":"not_materialized"},"state":"missing"},"projection_state":"missing","schema_version":1,"surface_guidance":{"forbidden_to_depend_fields":["results[].id"],"legacy_compatibility_fields":[],"preferred_response_fields":["results[].file_path","results[].start_line","results[].end_line","results[].name","results[].context_path","results","contract"]}},"count":10,"is_partial":false,"message":null,"next_actions":["Check project_info(action="status") for project readiness.","Treat vector/semantic ranking as degraded until semantic lifecycle is ready."],"query":"pub async fn index_project(state Arc AppState project_path Path)","readiness":{"available_channels":["bm25_search","symbol_search","ppr_graph"],"degraded_channels":["vector_search"],"is_degraded":true,"lifecycle":{"projection":{"is_current":false,"state":"stale"},"semantic":{"generation":0,"is_caught_up":false,"is_ready":false,"state":"pending"},"structural":{"generation":1,"is_ready":true,"state":"ready"}},"message":"Indexing in progress. Semantic (vector) search unavailable until complete.","source_path":"_indexing","status":"embedding_pending"},"results":[{"bm25_score":19.945720672607422,"chunk_type":"function","content":"pub async fn index_project(state: Arc<AppState>, project_path: &Path) -> Result<IndexStatus> {
    let project_id = project_path
        .file_name()
        .and_then(|n| n.to_str())
        .unwrap_or("unknown")
        .to_string();

    let state_clone = state.clone();
    let project_path_clone = project_path.to_path_buf();
    let project_id_clone = project_id.clone();

    // Spawn as a task so we can catch panics natively
    let handle = tokio::spawn(async move {
        do_index_project(state_clone, &project_path_clone, &project_id_clone).await
    });

    let result = match handle.await {
        Ok(res) => res,
        Err(join_err) => {
            let msg = if join_err.is_panic() {
                "Indexing panicked (crashed)".to_string()
            } else if join_err.is_cancelled() {
                "Indexing was cancelled".to_string()
            } else {
                "Indexing failed to complete".to_string()
            };
            Err(crate::AppError::Internal(msg.into()))
        }
    };

    match result {
        Ok(status) => Ok(status),
        Err(e) => {
            tracing::error!(project_id = %project_id, error = %e, "Indexing failed");
            let mut status = IndexStatus::new(project_id.clone());
            if let Ok(Some(existing)) = state.storage.get_index_status(&project_id).await {
                status = existing;
            }

            // Extract last known file if possible
            if let Some(monitor) = state.progress.get(&project_id).await {
                if let Ok(cf) = monitor.current_file.read() {
                    if !cf.is_empty() {
                        status.failed_files.push(cf.clone());
                        status.error_message = Some(format!("{}: Failed at file {}", e, cf));
                    } else {
                        status.error_message = Some(e.to_string());
                    }
                } else {
                    status.error_message = Some(e.to_string());
                }
            } else {
                status.error_message = Some(e.to_string());
            }

            status.status = IndexState::Failed;
            status.completed_at = Some(crate::types::Datetime::default());
            let _ = state.storage.update_index_status(status.clone()).await;
            Err(e)
        }
    }
