                                    target: Some(EmbeddingTarget::Chunk(id.clone())),
                                    retry_count: 0,
                                })
                                .await
                            {
                                tracing::warn!(chunk_id = %id, error = %e, "Failed to enqueue chunk embedding");
                            }
